import React, { useEffect, useState } from "react";
import API from "../../api/api";
import { useNavigate } from "react-router-dom";
import { T, fonts, Spinner, PageHeader, PrimaryBtn, GhostBtn, Badge, SVGIcon, Card } from "./designSystem";

const fmt = d => d ? new Date(d).toLocaleDateString("en-IN",{day:"2-digit",month:"short",year:"numeric"}) : "";

const MyProjects = () => {
  const navigate = useNavigate();
  const [projects,    setProjects]    = useState([]);
  const [submissions, setSubmissions] = useState({});
  const [loading,     setLoading]     = useState(true);

  useEffect(() => {
    (async () => {
      try {
        const data = (await API.get("/projects/client")).data || [];
        setProjects(data);
        const sc = {};
        await Promise.all(data.map(async p => {
          try { sc[p.id] = (await API.get(`/submissions/project/${p.id}`)).data?.length || 0; }
          catch { sc[p.id] = 0; }
        }));
        setSubmissions(sc);
      } catch {}
      setLoading(false);
    })();
  }, []);

  return (
    <div style={{ minHeight:"100vh", background:T.pageBg, fontFamily:"'DM Sans',sans-serif" }}>
      <link href={fonts} rel="stylesheet"/>
      <div style={{ maxWidth:1000, margin:"0 auto", padding:"36px 28px" }}>

        <PageHeader
          eyebrow="Project Management"
          title="My Projects"
          subtitle={!loading ? `${projects.length} project${projects.length!==1?"s":""} posted` : ""}
          action={
            <PrimaryBtn onClick={() => navigate("/client/post-project")}>
              <SVGIcon d="M12 4v16m8-8H4" color="#fff" size={14} stroke={2.5}/> Post New Project
            </PrimaryBtn>
          }
        />

        {loading ? <Card><Spinner/></Card> : projects.length === 0 ? (
          <Card>
            <div style={{ padding:"64px 20px", textAlign:"center" }}>
              <div style={{ fontSize:52, marginBottom:14 }}>📁</div>
              <h3 style={{ color:T.text, fontFamily:"'Syne',sans-serif", marginBottom:8 }}>No projects yet</h3>
              <p style={{ color:T.muted, marginBottom:24, fontSize:14 }}>Post your first project and hire talented freelancers</p>
              <PrimaryBtn onClick={() => navigate("/client/post-project")}>+ Post First Project</PrimaryBtn>
            </div>
          </Card>
        ) : (
          <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
            {projects.map(p => {
              const skills = p.skills ? p.skills.split(",").map(s=>s.trim()).filter(Boolean) : [];
              return (
                <div key={p.id} style={{ background:T.card, borderRadius:16,
                  border:`1px solid ${T.border}`, boxShadow:"0 1px 3px rgba(0,0,0,0.05)",
                  padding:"22px 26px", transition:"box-shadow .2s" }}
                  onMouseEnter={e=>e.currentTarget.style.boxShadow="0 4px 18px rgba(0,0,0,0.08)"}
                  onMouseLeave={e=>e.currentTarget.style.boxShadow="0 1px 3px rgba(0,0,0,0.05)"}>

                  {/* Top row */}
                  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:10 }}>
                    <div style={{ flex:1 }}>
                      <div style={{ display:"flex", alignItems:"center", gap:9, marginBottom:5 }}>
                        <h3 style={{ margin:0, fontSize:16, fontWeight:700, color:T.text,
                          fontFamily:"'Syne',sans-serif" }}>{p.title}</h3>
                        <Badge status={p.status||"open"}/>
                      </div>
                      <p style={{ margin:0, fontSize:13, color:T.muted, lineHeight:1.5,
                        maxWidth:580 }}>{p.description?.slice(0,110)}{p.description?.length>110?"...":""}</p>
                    </div>
                  </div>

                  {/* Meta */}
                  <div style={{ display:"flex", gap:16, fontSize:12, color:T.muted,
                    marginBottom:14, flexWrap:"wrap", alignItems:"center" }}>
                    <span style={{ display:"flex", alignItems:"center", gap:4 }}>
                      <SVGIcon d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" color={T.accent} size={13}/>
                      <strong style={{ color:T.text }}>₹{Number(p.budget).toLocaleString()}</strong>
                    </span>
                    {p.deadline && (
                      <span style={{ display:"flex", alignItems:"center", gap:4 }}>
                        <SVGIcon d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" color={T.muted} size={12}/>
                        {fmt(p.deadline)}
                      </span>
                    )}
                    {p.category && (
                      <span style={{ padding:"2px 9px", background:"#EFF6FF", color:"#3B82F6",
                        borderRadius:6, fontSize:11, fontWeight:600 }}>
                        {p.category.replace(/-/g," ").replace(/\b\w/g,l=>l.toUpperCase())}
                      </span>
                    )}
                  </div>

                  {/* Skills */}
                  {skills.length > 0 && (
                    <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginBottom:16 }}>
                      {skills.slice(0,5).map(s => (
                        <span key={s} style={{ padding:"2px 9px", background:"#F8FAFC",
                          border:`1px solid ${T.border}`, borderRadius:6, fontSize:11,
                          color:"#475569", fontWeight:500 }}>{s}</span>
                      ))}
                    </div>
                  )}

                  {/* Buttons */}
                  <div style={{ display:"flex", gap:10, paddingTop:12,
                    borderTop:`1px solid ${T.border}` }}>
                    <PrimaryBtn small onClick={() => navigate(`/client/projects/${p.id}/proposals`)}>
                      <SVGIcon d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" color="#fff" size={13}/>
                      View Proposals
                    </PrimaryBtn>
                    <GhostBtn small onClick={() => navigate(`/client/projects/${p.id}/submissions`)}>
                      <SVGIcon d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" color={T.accent} size={13}/>
                      Submissions
                      {submissions[p.id] > 0 && (
                        <span style={{ background:T.accent, color:"#fff", fontSize:10, fontWeight:700,
                          width:17, height:17, borderRadius:"50%", display:"flex",
                          alignItems:"center", justifyContent:"center" }}>
                          {submissions[p.id]}
                        </span>
                      )}
                    </GhostBtn>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};
export default MyProjects;
